import express from 'express';
import http from 'http';
import cors from 'cors';
import { Server as SocketIOServer } from 'socket.io';
import { nanoid } from 'nanoid';
import dotenv from 'dotenv';
import fs from 'fs';
import path from 'path';
import axios from 'axios';

dotenv.config();

const PORT = process.env.PORT || 3001;
const DATA_DIR = process.env.DATA_DIR || path.join(process.cwd(), 'data');
fs.mkdirSync(DATA_DIR, { recursive: true });

// Simple JSON file store
const dbPath = (name) => path.join(DATA_DIR, `${name}.json`);
const load = (name, fallback) => {
  try {
    const p = dbPath(name);
    if (!fs.existsSync(p)) return fallback;
    return JSON.parse(fs.readFileSync(p, 'utf-8'));
  } catch (e) {
    console.error('Failed to load', name, e);
    return fallback;
  }
};
const save = (name, value) => {
  try {
    fs.writeFileSync(dbPath(name), JSON.stringify(value, null, 2));
  } catch (e) {
    console.error('Failed to save', name, e);
  }
};

// In-memory state with persistence
const state = {
  participants: load('participants', {}), // id -> {id, type: 'person'|'agent', name, avatarUrl?, agent?: AgentConfig}
  threads: load('threads', {}), // id -> {id, name, createdAt, participants: [id], messages: [...]} 
};

function createThread(name = 'New Thread') {
  const id = nanoid();
  const thread = { id, name, createdAt: new Date().toISOString(), participants: [], messages: [] };
  state.threads[id] = thread;
  save('threads', state.threads);
  return thread;
}

function ensureDefaultThread() {
  if (Object.keys(state.threads).length === 0) {
    const t = createThread('General');
    console.log('Created default thread', t.id);
  }
}

ensureDefaultThread();

// Agent runner abstraction
async function runAgentMessage(agent, thread, userMessage) {
  const context = buildContext(agent, thread);
  // Append the triggering user message at end of context
  const messages = [...context, { role: 'user', content: userMessage.content }];
  try {
    if (agent.agent.provider === 'stub') {
      const resp = await runStubAgent(agent, messages);
      return resp;
    } else if (agent.agent.provider === 'openai' || agent.agent.provider === 'openai-compatible') {
      const resp = await runOpenAICompatible(agent, messages);
      return resp;
    } else {
      return { content: `(agent ${agent.name}) provider ${agent.agent.provider} not implemented.` };
    }
  } catch (e) {
    console.error('Agent run error', e);
    return { content: `Agent ${agent.name} error: ${e.message || e}` };
  }
}

function buildContext(agent, thread) {
  const systemPrompt = agent.agent.systemPrompt || `You are ${agent.name}, role: ${agent.agent.role || 'assistant'}.`;
  // Map last N messages into chat format excluding tool messages
  const last = thread.messages.slice(-30).map(m => ({
    role: m.role === 'agent' ? 'assistant' : m.role,
    content: m.content
  }));
  return [{ role: 'system', content: systemPrompt }, ...last];
}

async function runStubAgent(agent, messages) {
  // Simple echo + suggestion
  const last = messages[messages.length - 1]?.content || '';
  const content = `Stub(${agent.name}): I read: "${last.slice(0, 140)}"...\n- Plan: ${agent.agent.role ? 'as ' + agent.agent.role + ', ' : ''}I will suggest next steps.\n- Next: Ask clarifying questions if needed.`;
  await delay(300);
  return { content };
}

async function runOpenAICompatible(agent, messages) {
  const baseURL = agent.agent.baseUrl || 'https://api.openai.com/v1';
  const model = agent.agent.model || 'gpt-4o-mini';
  const apiKey = agent.agent.apiKey || process.env.OPENAI_API_KEY;
  if (!apiKey) {
    return { content: `Agent ${agent.name} missing API key. Add OPENAI_API_KEY in server env or set agent.apiKey.` };
  }
  const payload = { model, messages, temperature: agent.agent.temperature ?? 0.5, stream: false };
  const resp = await axios.post(`${baseURL}/chat/completions`, payload, {
    headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }
  });
  const content = resp.data?.choices?.[0]?.message?.content || '(no content)';
  return { content };
}

function delay(ms){return new Promise(r=>setTimeout(r,ms));}

const app = express();
app.use(cors({ origin: '*'}));
app.use(express.json({ limit: '1mb' }));

// Serve static client build if available
const clientDist = path.resolve(process.cwd(), '../client/dist');
if (fs.existsSync(clientDist)) {
  app.use(express.static(clientDist));
}

const server = http.createServer(app);
const io = new SocketIOServer(server, { cors: { origin: '*' } });

io.on('connection', (socket) => {
  // Client can join thread rooms
  socket.on('join_thread', (threadId) => {
    socket.join(`thread:${threadId}`);
  });
  socket.on('leave_thread', (threadId) => {
    socket.leave(`thread:${threadId}`);
  });
});

function emitThreadUpdate(threadId) {
  const thread = state.threads[threadId];
  io.to(`thread:${threadId}`).emit('thread_update', thread);
}

// API routes
app.get('/api/threads', (req, res) => {
  const threads = Object.values(state.threads).sort((a,b)=>a.createdAt.localeCompare(b.createdAt));
  res.json(threads);
});

app.post('/api/threads', (req, res) => {
  const name = req.body?.name || 'New Thread';
  const t = createThread(name);
  res.json(t);
  emitThreadUpdate(t.id);
});

app.get('/api/threads/:id', (req, res) => {
  const t = state.threads[req.params.id];
  if (!t) return res.status(404).json({ error: 'thread not found' });
  res.json(t);
});

app.post('/api/threads/:id/participants', (req, res) => {
  const t = state.threads[req.params.id];
  if (!t) return res.status(404).json({ error: 'thread not found' });
  const participant = req.body; // either existing id or new definition
  let p;
  if (participant.id && state.participants[participant.id]) {
    p = state.participants[participant.id];
  } else {
    const id = nanoid();
    p = { id, type: participant.type || 'person', name: participant.name || 'Unnamed', avatarUrl: participant.avatarUrl, agent: participant.agent };
    state.participants[id] = p;
    save('participants', state.participants);
  }
  if (!t.participants.includes(p.id)) t.participants.push(p.id);
  save('threads', state.threads);
  res.json({ thread: t, participant: p });
  emitThreadUpdate(t.id);
});

app.get('/api/participants', (req, res) => {
  res.json(Object.values(state.participants));
});

app.post('/api/agents', (req, res) => {
  const body = req.body || {};
  const id = nanoid();
  const p = { id, type: 'agent', name: body.name || 'Agent', avatarUrl: body.avatarUrl, agent: {
    provider: body.provider || 'stub',
    baseUrl: body.baseUrl,
    model: body.model,
    apiKey: body.apiKey, // optional; prefer env
    role: body.role,
    systemPrompt: body.systemPrompt,
    temperature: body.temperature ?? 0.5,
  }};
  state.participants[id] = p;
  save('participants', state.participants);
  res.json(p);
});

app.get('/api/agents', (req, res) => {
  const agents = Object.values(state.participants).filter(p => p.type === 'agent');
  res.json(agents);
});

app.post('/api/threads/:id/messages', async (req, res) => {
  const t = state.threads[req.params.id];
  if (!t) return res.status(404).json({ error: 'thread not found' });
  const { senderId, content, targetAgents } = req.body || {};
  if (!content) return res.status(400).json({ error: 'content required' });

  const sender = senderId ? state.participants[senderId] : null;
  const role = sender && sender.type === 'agent' ? 'agent' : 'user';

  const msg = { id: nanoid(), threadId: t.id, role, senderId: sender?.id, content, createdAt: new Date().toISOString() };
  t.messages.push(msg);
  save('threads', state.threads);
  emitThreadUpdate(t.id);

  res.json({ ok: true, message: msg });

  // Trigger agents if requested
  const agentsToRun = (targetAgents || []).map(id => state.participants[id]).filter(Boolean);
  for (const agent of agentsToRun) {
    const reply = await runAgentMessage(agent, t, msg);
    const aMsg = { id: nanoid(), threadId: t.id, role: 'agent', senderId: agent.id, content: reply.content, createdAt: new Date().toISOString() };
    t.messages.push(aMsg);
    save('threads', state.threads);
    emitThreadUpdate(t.id);
  }
});

app.get('/api/health', (req, res) => {
  res.json({ ok: true });
});

server.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

