    p = { id, type: participant.type || 'person', name: participant.name || 'Unnamed', avatarUrl: participant.avatarUrl, agent: participant.agent };
    state.participants[id] = p;
    save('participants', state.participants);
  }
  if (!t.participants.includes(p.id)) t.participants.push(p.id);
  save('threads', state.threads);
  res.json({ thread: t, participant: p });
  emitThreadUpdate(t.id);
});

app.get('/api/participants', (req, res) => {
  res.json(Object.values(state.participants));
});

app.post('/api/agents', (req, res) => {
  const body = req.body || {};
  const id = nanoid();
  const p = { id, type: 'agent', name: body.name || 'Agent', avatarUrl: body.avatarUrl, agent: {
    provider: body.provider || 'stub',
    baseUrl: body.baseUrl,
    model: body.model,
    apiKey: body.apiKey, // optional; prefer env
    role: body.role,
    systemPrompt: body.systemPrompt,
    temperature: body.temperature ?? 0.5,
  }};
  state.participants[id] = p;
  save('participants', state.participants);
  res.json(p);
});

app.get('/api/agents', (req, res) => {
  const agents = Object.values(state.participants).filter(p => p.type === 'agent');
  res.json(agents);
});

app.post('/api/threads/:id/messages', async (req, res) => {
  const t = state.threads[req.params.id];
  if (!t) return res.status(404).json({ error: 'thread not found' });
  const { senderId, content, targetAgents } = req.body || {};
  if (!content) return res.status(400).json({ error: 'content required' });

  const sender = senderId ? state.participants[senderId] : null;
  const role = sender and sender.type === 'agent' ? 'agent' : 'user';

  const msg = { id: nanoid(), threadId: t.id, role, senderId: sender?.id, content, createdAt: new Date().toISOString() };
  t.messages.push(msg);
  save('threads', state.threads);
  emitThreadUpdate(t.id);

  res.json({ ok: true, message: msg });

  // Trigger agents if requested
  const agentsToRun = (targetAgents || []).map(id => state.participants[id]).filter(Boolean);
  for (const agent of agentsToRun) {
    const reply = await runAgentMessage(agent, t, msg);
    const aMsg = { id: nanoid(), threadId: t.id, role: 'agent', senderId: agent.id, content: reply.content, createdAt: new Date().toISOString() };
    t.messages.push(aMsg);
    save('threads', state.threads);
    emitThreadUpdate(t.id);
  }
});

app.get('/api/health', (req, res) => {
  res.json({ ok: true });
});

server.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});
