import React, { useEffect, useMemo, useRef, useState } from 'react'
import { io } from 'socket.io-client'
import { clsx } from 'clsx'

const socket = io()

function useLocalStorage(key, initial) {
  const [value, setValue] = useState(() => {
    const v = localStorage.getItem(key)
    return v ? JSON.parse(v) : initial
  })
  useEffect(() => {
    localStorage.setItem(key, JSON.stringify(value))
  }, [key, value])
  return [value, setValue]
}

export default function App() {
  const [threads, setThreads] = useState([])
  const [currentThreadId, setCurrentThreadId] = useState(null)
  const [currentThread, setCurrentThread] = useState(null)
  const [participants, setParticipants] = useState([])
  const [me, setMe] = useLocalStorage('me', { name: 'Me', id: null })
  const [rightOpen, setRightOpen] = useState(false)
  const [mobileTab, setMobileTab] = useState('chat')
  const [compose, setCompose] = useState('')
  const [selectedAgents, setSelectedAgents] = useState([])

  useEffect(() => { fetchThreads() }, [])
  useEffect(() => {
    const u = new URL(window.location.href)
    const t = u.searchParams.get('t')
    if (t) setCurrentThreadId(t)
  }, [])
  useEffect(() => { fetchParticipants() }, [])

  useEffect(() => {
    if (!currentThreadId) return
    socket.emit('join_thread', currentThreadId)
    fetchThread(currentThreadId)
    const handler = (t) => { if (t.id === currentThreadId) setCurrentThread(t) }
    socket.on('thread_update', handler)
    return () => {
      socket.emit('leave_thread', currentThreadId)
      socket.off('thread_update', handler)
    }
  }, [currentThreadId])

  async function fetchThreads() {
    const r = await fetch('/api/threads')
    const data = await r.json()
    setThreads(data)
    if (!currentThreadId && data[0]) setCurrentThreadId(data[0].id)
  }
  async function fetchThread(id) {
    const r = await fetch(`/api/threads/${id}`)
    if (r.ok) setCurrentThread(await r.json())
  }
  async function fetchParticipants() {
    const r = await fetch('/api/participants')
    setParticipants(await r.json())
  }
  async function newThread() {
    const name = prompt('Thread name?') || 'New Thread'
    const r = await fetch('/api/threads', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ name }) })
    const t = await r.json()
    setThreads(prev => [...prev, t])
    setCurrentThreadId(t.id)
  }

  const agents = participants.filter(p => p.type === 'agent')

  async function ensureMeParticipant() {
    if (me.id && participants.find(p=>p.id===me.id)) return me
    // create person
    const current = await (await fetch(`/api/threads/${currentThreadId}`)).json()
    const r = await fetch(`/api/threads/${currentThreadId}/participants`, { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ type: 'person', name: me.name }) })
    const d = await r.json()
    const created = d.participant
    setMe({ name: created.name, id: created.id })
    await fetchParticipants()
    setCurrentThread(d.thread)
    return created
  }

  async function sendMessage() {
    if (!compose.trim()) return
    const sender = await ensureMeParticipant()
    const payload = { senderId: sender.id, content: compose, targetAgents: selectedAgents }
    setCompose('')
    setSelectedAgents([])
    await fetch(`/api/threads/${currentThreadId}/messages`, { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(payload) })
  }

  function ParticipantPill({ p, onClick, active }){
    return (
      <button onClick={onClick} className={clsx('px-2 py-1 rounded-full text-sm mr-2 mb-2 border', active ? 'bg-blue-600 text-white border-blue-600' : 'bg-neutral-100 dark:bg-neutral-800 text-neutral-800 dark:text-neutral-100 border-neutral-300 dark:border-neutral-700')}>{p.name}</button>
    )
  }

  function AddAgentForm(){
    const [name, setName] = useState('Planner')
    const [provider, setProvider] = useState('stub')
    const [model, setModel] = useState('gpt-4o-mini')
    const [baseUrl, setBaseUrl] = useState('')
    const [apiKey, setApiKey] = useState('')
    const [role, setRole] = useState('planning')
    const [systemPrompt, setSystemPrompt] = useState('You are a helpful agent focused on planning and coordination.')
    const [temperature, setTemperature] = useState(0.3)

    async function create(){
      const r = await fetch('/api/agents', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ name, provider, model, baseUrl, apiKey, role, systemPrompt, temperature }) })
      const agent = await r.json()
      await fetchParticipants()
      // add to thread
      await fetch(`/api/threads/${currentThreadId}/participants`, { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ id: agent.id }) })
      await fetchThread(currentThreadId)
    }

    return (
      <div className="space-y-2">
        <h3 className="font-semibold">Add Agent</h3>
        <input className="w-full p-2 rounded border bg-white dark:bg-neutral-800" placeholder="Agent name" value={name} onChange={e=>setName(e.target.value)} />
        <label className="block text-sm">Provider</label>
        <select className="w-full p-2 rounded border bg-white dark:bg-neutral-800" value={provider} onChange={e=>setProvider(e.target.value)}>
          <option value="stub">Stub (no API key)</option>
          <option value="openai">OpenAI</option>
          <option value="openai-compatible">OpenAI-compatible (Ollama/LM Studio)</option>
        </select>
        <input className="w-full p-2 rounded border bg-white dark:bg-neutral-800" placeholder="Model (e.g. gpt-4o-mini or llama3)" value={model} onChange={e=>setModel(e.target.value)} />
        <input className="w-full p-2 rounded border bg-white dark:bg-neutral-800" placeholder="Base URL (optional)" value={baseUrl} onChange={e=>setBaseUrl(e.target.value)} />
        <input className="w-full p-2 rounded border bg-white dark:bg-neutral-800" placeholder="API Key (optional; else server env)" value={apiKey} onChange={e=>setApiKey(e.target.value)} />
        <input className="w-full p-2 rounded border bg-white dark:bg-neutral-800" placeholder="Role (e.g. planning, coding)" value={role} onChange={e=>setRole(e.target.value)} />
        <textarea className="w-full p-2 rounded border bg-white dark:bg-neutral-800" placeholder="System prompt" value={systemPrompt} onChange={e=>setSystemPrompt(e.target.value)} />
        <label className="block text-sm">Temperature: {temperature}</label>
        <input type="range" min="0" max="1" step="0.1" value={temperature} onChange={e=>setTemperature(parseFloat(e.target.value))} />
        <button onClick={create} className="w-full py-2 rounded bg-blue-600 text-white">Create Agent</button>
      </div>
    )
  }

  function AddPersonForm(){
    const [name, setName] = useState('Teammate')
    async function create(){
      const r = await fetch(`/api/threads/${currentThreadId}/participants`, { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ type: 'person', name }) })
      const d = await r.json()
      await fetchParticipants()
      await fetchThread(currentThreadId)
    }
    return (
      <div className="space-y-2">
        <h3 className="font-semibold">Invite Person</h3>
        <input className="w-full p-2 rounded border bg-white dark:bg-neutral-800" placeholder="Display name" value={name} onChange={e=>setName(e.target.value)} />
        <button onClick={create} className="w-full py-2 rounded bg-neutral-700 text-white">Add</button>
      </div>
    )
  }

  const isMobile = useMedia('(max-width: 900px)')

  return (
    <div className="h-screen flex flex-col">
      <header className="flex items-center justify-between px-3 py-2 border-b bg-white/60 dark:bg-neutral-900/60 backdrop-blur sticky top-0 z-10">
        <div className="flex items-center gap-2">
          <button className="md:hidden px-2 py-1 rounded border" onClick={()=>setMobileTab(mobileTab==='sidebar'?'chat':'sidebar')}>☰</button>
          <span className="font-semibold">Multi-Agent Chat</span>
        </div>
        <div className="flex items-center gap-2">
          <input className="px-2 py-1 rounded border w-36" value={me.name} onChange={e=>setMe(m=>({...m, name: e.target.value}))} />
          <button className="px-2 py-1 rounded border" onClick={()=>setRightOpen(o=>!o)}>Team</button>
        </div>
      </header>

      <div className="flex flex-1 min-h-0">
        {(mobileTab==='sidebar' || !isMobile) && (
          <aside className="w-64 shrink-0 border-r p-3 overflow-auto">
            <div className="flex items-center justify-between mb-2">
              <h2 className="font-semibold">Threads</h2>
              <button className="px-2 py-1 rounded border" onClick={newThread}>New</button>
            </div>
            <div className="space-y-1">
              {threads.map(t=> (
                <button key={t.id} onClick={()=>{setCurrentThreadId(t.id); setMobileTab('chat')}} className={clsx('w-full text-left px-2 py-1 rounded', currentThreadId===t.id ? 'bg-blue-100 dark:bg-blue-900' : 'hover:bg-neutral-100 dark:hover:bg-neutral-800')}>{t.name}</button>
              ))}
            </div>
          </aside>
        )}

        <main className="flex-1 flex flex-col min-w-0">
          <div className="flex-1 overflow-auto p-3 space-y-3">
            {!currentThread && <div className="text-sm text-neutral-500">Loading...</div>}
            {currentThread && currentThread.messages.map(m => (
              <div key={m.id} className={clsx('max-w-[85%] md:max-w-[70%] px-3 py-2 rounded shadow text-sm', m.role==='agent'? 'self-start bg-white dark:bg-neutral-800 border': 'self-end bg-blue-600 text-white')}>
                <div className="text-[11px] opacity-70 mb-1">{labelFor(m.senderId, m.role, participants)}</div>
                <div className="whitespace-pre-wrap">{m.content}</div>
              </div>
            ))}
            <div ref={el=>{ if (el) el.scrollIntoView({behavior:'smooth'}); }} />
          </div>
          <div className="border-t p-3 flex flex-col gap-2">
            <div className="flex gap-2 items-center overflow-auto">
              {currentThread && currentThread.participants
                .map(id => participants.find(p=>p.id===id))
                .filter(Boolean)
                .filter(p=>p.type==='agent')
                .map(p => (
                  <ParticipantPill key={p.id} p={p} active={selectedAgents.includes(p.id)} onClick={()=> setSelectedAgents(sel=> sel.includes(p.id) ? sel.filter(x=>x!==p.id) : [...sel, p.id])} />
                ))}
            </div>
            <div className="flex gap-2">
              <textarea rows={2} value={compose} onChange={e=>setCompose(e.target.value)} className="flex-1 p-2 rounded border" placeholder="Message the team..." />
              <button onClick={sendMessage} className="px-4 py-2 rounded bg-blue-600 text-white">Send</button>
            </div>
          </div>
        </main>

        {(rightOpen && (mobileTab==='team' || !isMobile)) && (
          <aside className="w-80 shrink-0 border-l p-3 overflow-auto">
            <h2 className="font-semibold mb-2">Team & Roles</h2>
            <div className="mb-4">
              <h3 className="font-semibold">Participants</h3>
              <div className="flex flex-wrap mt-2">
                {currentThread && currentThread.participants.map(id => {
                  const p = participants.find(x=>x.id===id)
                  if (!p) return null
                  return <ParticipantPill key={p.id} p={p} />
                })}
              </div>
            </div>
            <div className="grid md:grid-cols-1 gap-4">
              <AddAgentForm />
              <AddPersonForm />
            </div>
          </aside>
        )}
      </div>

      {isMobile && (
        <nav className="border-t flex">
          <button className={tabBtn(mobileTab==='chat')} onClick={()=>setMobileTab('chat')}>Chat</button>
          <button className={tabBtn(mobileTab==='team')} onClick={()=>setMobileTab('team')}>Team</button>
          <button className={tabBtn(mobileTab==='sidebar')} onClick={()=>setMobileTab('sidebar')}>Threads</button>
        </nav>
      )}
    </div>
  )
}

function useMedia(query){
  const [match, setMatch] = useState(()=> window.matchMedia(query).matches)
  useEffect(()=>{
    const mq = window.matchMedia(query)
    const h = (e)=> setMatch(e.matches)
    mq.addEventListener('change', h)
    return ()=> mq.removeEventListener('change', h)
  }, [query])
  return match
}

function tabBtn(active){
  return clsx('flex-1 py-2', active ? 'bg-blue-600 text-white' : 'bg-white dark:bg-neutral-900')
}

function labelFor(senderId, role, participants){
  if (senderId){
    const p = participants.find(p=>p.id===senderId)
    if (p) return p.name
  }
  return role === 'agent' ? 'Agent' : 'You'
}
EOF

