# Patch server runOpenAICompatible to allow no API key for openai-compatible and to handle missing /v1 in baseUrl
FILE=~/agent-workspace/multiagent-chat/server/src/index.js
cp "$FILE" "$FILE.bak_$(date +%s)"
# Use awk to replace the runOpenAICompatible function block
awk '
  BEGIN{infunc=0}
  /async function runOpenAICompatible\(agent, messages\) \{/ {infunc=1; print;
    print "  const provider = agent.agent.provider || \"openai-compatible\";";
    print "  const rawBase = (agent.agent.baseUrl || (provider === \"openai\" ? \"https://api.openai.com/v1\" : \"\")).trim();";
    print "  // Normalize base URL and endpoint";
    print "  let baseURL = rawBase.replace(/\\/+$/, \"\");";
    print "  if (!baseURL) { baseURL = \"https://api.openai.com/v1\"; }";
    print "  const endsWithV1 = /\\/v1$/.test(baseURL);";
    print "  const endpoint = (endsWithV1 ? baseURL : baseURL + \"/v1\") + \"/chat/completions\";";
    print "  const model = agent.agent.model || (provider === \"openai\" ? \"gpt-4o-mini\" : \"llama3\");";
    print "  const apiKey = agent.agent.apiKey || process.env.OPENAI_API_KEY || \"\";";
    print "  // For provider=openai, API key is required. For openai-compatible (e.g., Ollama), allow no key.";
    print "  if (provider === \"openai\" && !apiKey) {";
    print "    return { content: `Agent ${agent.name} missing API key. Add OPENAI_API_KEY in server env or set agent.apiKey.` };";
    print "  }";
    print "  const payload = { model, messages, temperature: agent.agent.temperature ?? 0.5, stream: false };";
    print "  const headers = { 'Content-Type': 'application/json' };";
    print "  if (apiKey) headers['Authorization'] = `Bearer ${apiKey}`;";
    print "  const resp = await axios.post(endpoint, payload, { headers });";
    print "  const content = resp.data?.choices?.[0]?.message?.content || '(no content)';";
    print "  return { content };";
    next
  }
  {
    if(infunc){
      # Skip original lines of the function until its closing brace
      if(/}\s*$/){ infunc=0; next }
      next
    }
    print
  }
' "$FILE" > "$FILE.tmp"
mv "$FILE.tmp" "$FILE"

# Show diff context around function
